#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        long long cells = N * M;
        long long total = cells * (cells - 1);
        long long attack = 0;
        if(N >= 2 && M >= 3) attack += 4LL * (N - 1) * (M - 2);
        if(N >= 3 && M >= 2) attack += 4LL * (N - 2) * (M - 1);
        printf("%lld\n", total - attack);
    }
    return 0;
}

